const app = express();
app.use(express.json({ limit: "10mb" }));

// ── EMBEDDED IMAGES ──────────────────────────────────────────────────────────
const COVER_IMG   = "image/png;base64,";
const CLOSING_IMG = "image/png;base64,";
const LOGO_IMG    = "image/png;base64,";

// ── CONSTANTS ────────────────────────────────────────────────────────────────
const NAVY       = "156082";
const TEAL       = "04AF87";
const TRANSIT_BG = "FFCCCC";
const DIRECT_BG  = "CCFFCC";
const WHITE      = "FFFFFF";
const GREY       = "F2F2F2";
const BORDER     = "C8D8E8";
const DARK       = "222222";
const FONT       = "DIN Next LT Arabic";
const TABLE_X    = 0.18;
const HEADER_H   = 0.75;
const ROW_H      = 0.48;
const COL        = [0.22, 1.28, 1.28, 1.65, 1.22, 1.22, 0.98, 1.14, 1.82, 2.15];
const BAND_X     = 0.65;
const BAND_Y     = 5.63;
const BAND_W     = 12.04;
const BAND_H     = 1.37;
const BAND_COLOR = "031E39";
const BAND_TRANS = 47;

// ── HELPERS ──────────────────────────────────────────────────────────────────
function httpsPost(hostname, path, headers, body) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const req = https.request({ hostname, path, method:"POST",
      headers:{ ...headers, "Content-Type":"application/json", "Content-Length":Buffer.byteLength(data) }
    }, res => {
      let raw = "";
      res.on("data", c => raw += c);
      res.on("end", () => { try { resolve(JSON.parse(raw)); } catch(e) { resolve(raw); } });
    });
    req.on("error", reject);
    req.write(data);
    req.end();
  });
}

function httpsGet(hostname, path, headers) {
  return new Promise((resolve, reject) => {
    const req = https.request({ hostname, path, method:"GET", headers }, res => {
      let raw = "";
      res.on("data", c => raw += c);
      res.on("end", () => { try { resolve(JSON.parse(raw)); } catch(e) { resolve(raw); } });
    });
    req.on("error", reject);
    req.end();
  });
}

function parseDuration(iso) {
  if (!iso) return "";
  const m = iso.match(/PT(?:(\d+)H)?(?:(\d+)M)?/);
  if (!m) return iso;
  const h = parseInt(m[1]||0);
  const min = parseInt(m[2]||0);
  return String(h).padStart(2,"0") + ":" + String(min).padStart(2,"0");
}

function formatDate(dateStr) {
  const d = new Date(dateStr);
  const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  const days = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"];
  return {
    date: String(d.getDate()).padStart(2,"0") + " " + months[d.getMonth()] + " " + d.getFullYear(),
    day: days[d.getDay()]
  };
}

function addDays(dateStr, n) {
  const d = new Date(dateStr);
  d.setDate(d.getDate() + n);
  return d.toISOString().split("T")[0];
}

async function mkIcon(svg) {
  const buf = await sharp(Buffer.from(svg)).resize(160,160).png().toBuffer();
  return "image/png;base64," + buf.toString("base64");
}

// ── AMADEUS TOKEN ─────────────────────────────────────────────────────────────
async function getAmadeusToken(clientId, clientSecret) {
  return new Promise((resolve, reject) => {
    const body = "grant_type=client_credentials&client_id=" + clientId + "&client_secret=" + clientSecret;
    const req = https.request({
      hostname: "test.api.amadeus.com",
      path: "/v1/security/oauth2/token",
      method: "POST",
      headers: { "Content-Type":"application/x-www-form-urlencoded", "Content-Length":Buffer.byteLength(body) }
    }, res => {
      let raw = "";
      res.on("data", c => raw += c);
      res.on("end", () => { try { resolve(JSON.parse(raw)); } catch(e) { reject(e); } });
    });
    req.on("error", reject);
    req.write(body);
    req.end();
  });
}

// ── AMADEUS FLIGHT SEARCH ─────────────────────────────────────────────────────
async function searchFlights(token, from, to, date) {
  const path = "/v2/shopping/flight-offers?originLocationCode=" + from +
    "&destinationLocationCode=" + to + "&departureDate=" + date +
    "&adults=1&max=10&nonStop=false";
  const result = await httpsGet("test.api.amadeus.com", path, {
    "Authorization": "Bearer " + token
  });
  return result.data || [];
}

// ── CLAUDE FILTER ─────────────────────────────────────────────────────────────
async function claudeFilter(offers, claudeKey) {
  const prompt = "You are a flight data processor. Analyze these Amadeus flight offers and return ONLY a JSON array, no other text, no markdown.\n\nIMPORTANT: Convert ALL ISO durations to HH:MM. PT6H50M = 06:50, PT1H30M = 01:30.\n\nRules:\n1. Class priority: FIRST > BUSINESS > ECONOMY\n2. Include all flights\n3. Remove layovers over 3 hours\n4. Sort by departure time ascending\n5. Remove duplicate flight numbers on same date\n\nEach object in array:\n- num: sequential from 1\n- airline: full name\n- cls: First or Business or Economy or Sold Out\n- direct: true or false\n- date: DD MMM YYYY\n- day: weekday name\n- legs: [{from, ft, to, at, no, dur, total(first leg only), transit(second leg only)}]\n\nData: " + JSON.stringify(offers);

  const result = await httpsPost("api.anthropic.com", "/v1/messages", {
    "x-api-key": claudeKey,
    "anthropic-version": "2023-06-01"
  }, {
    model: "claude-sonnet-4-20250514",
    max_tokens: 4000,
    messages: [{ role:"user", content: prompt }]
  });

  const text = result.content && result.content[0] && result.content[0].text || "[]";
  const cleaned = text.replace(/```json/g,"").replace(/```/g,"").trim();
  try { return JSON.parse(cleaned); } catch(e) { return []; }
}

// ── POWERPOINT GENERATOR ──────────────────────────────────────────────────────
async function generatePPTX(flights, legLabel, missionDate) {
  const pinPng = await mkIcon('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32"><path d="M16 2C10.48 2 6 6.48 6 12c0 7.5 10 18 10 18S26 19.5 26 12c0-5.52-4.48-10-10-10z" fill="#11A77C"/><circle cx="16" cy="12" r="4" fill="white"/><circle cx="16" cy="12" r="2" fill="#11A77C"/></svg>');
  const calPng = await mkIcon('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32"><rect x="2" y="5" width="28" height="24" rx="3" fill="#04AF87"/><rect x="2" y="5" width="28" height="10" rx="3" fill="#038060"/><rect x="2" y="12" width="28" height="3" fill="#038060"/><rect x="9" y="1" width="3" height="7" rx="1.5" fill="#04AF87"/><rect x="20" y="1" width="3" height="7" rx="1.5" fill="#04AF87"/><rect x="6" y="18" width="4" height="4" rx="1" fill="white"/><rect x="14" y="18" width="4" height="4" rx="1" fill="white"/><rect x="22" y="18" width="4" height="4" rx="1" fill="white"/><rect x="6" y="24" width="4" height="3" rx="1" fill="white"/><rect x="14" y="24" width="4" height="3" rx="1" fill="white"/></svg>');
  const starPng = await mkIcon('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32"><polygon points="16,3 19.5,11.5 29,12.5 22.5,19 24.5,28.5 16,24 7.5,28.5 9.5,19 3,12.5 12.5,11.5" fill="#156082" stroke="#156082" stroke-width="0.5"/></svg>');
  const bagPng = await mkIcon('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32"><rect x="3" y="11" width="26" height="17" rx="3" fill="#04AF87"/><rect x="10" y="5" width="12" height="7" rx="2" fill="#04AF87" stroke="#038060" stroke-width="1.5"/><rect x="14" y="10" width="4" height="8" rx="1" fill="white"/><rect x="3" y="17" width="26" height="3" fill="white" opacity="0.35"/></svg>');

  const pres = new pptxgen();
  pres.layout = "LAYOUT_WIDE";

  // COVER
  const cover = pres.addSlide();
  cover.addImage({ data:COVER_IMG, x:0, y:0, w:13.33, h:7.5 });
  cover.addShape(pres.shapes.RECTANGLE, { x:BAND_X, y:BAND_Y, w:BAND_W, h:BAND_H, fill:{ type:"solid", color:BAND_COLOR, transparency:BAND_TRANS }, line:{ type:"none" } });
  const BADGE_W=1.5, BADGE_H=0.32, BADGE_X=BAND_X+BAND_W-BADGE_W, BADGE_Y=BAND_Y+0.01;
  cover.addShape(pres.shapes.RECTANGLE, { x:BADGE_X, y:BADGE_Y, w:BADGE_W, h:BADGE_H, fill:{ type:"solid", color:TEAL }, line:{ type:"none" } });
  cover.addText(missionDate||"2026", { x:BADGE_X, y:BADGE_Y, w:BADGE_W, h:BADGE_H, fontSize:11, bold:true, color:WHITE, fontFace:FONT, align:"center", valign:"middle" });
  cover.addImage({ data:LOGO_IMG, x:0.85, y:5.94, w:3.44, h:0.75 });
  cover.addText("Suggested Flights Schedule", { x:4.6, y:BAND_Y, w:7.8, h:BAND_H, fontSize:32, bold:true, color:WHITE, fontFace:FONT, align:"right", valign:"middle" });

  // FLIGHT DATA SLIDE
  const dateMap = {};
  let di = 0;
  for (const f of flights) {
    const key = f.date || String(f.num);
    if (!(key in dateMap)) dateMap[key] = di++ % 2;
    f._bgKey = key;
  }

  const s = pres.addSlide();
  s.background = { color:WHITE };
  s.addText("Suggested Flight Schedule \u2013 " + legLabel, { x:0.3, y:0, w:6.8, h:HEADER_H, fontSize:17, bold:true, color:NAVY, fontFace:FONT, align:"left", valign:"middle" });
  s.addShape(pres.shapes.LINE, { x:7.32, y:0.14, w:0, h:HEADER_H-0.28, line:{color:"CCCCCC",width:1} });
  s.addShape(pres.shapes.LINE, { x:10.24, y:0.14, w:0, h:HEADER_H-0.28, line:{color:"CCCCCC",width:1} });
  s.addImage({ data:pinPng, x:7.48, y:0.14, w:0.34, h:0.42 });
  s.addText("Visit Location", { x:7.88, y:0.02, w:2.3, h:0.24, fontSize:11, bold:true, color:"888888", fontFace:FONT });
  s.addText(legLabel.split(" to ")[1]||legLabel, { x:7.88, y:0.30, w:2.3, h:0.26, fontSize:10.5, bold:true, color:NAVY, fontFace:FONT });
  s.addImage({ data:calPng, x:10.38, y:0.14, w:0.36, h:0.42 });
  s.addText("Mission Date", { x:10.80, y:0.02, w:2.3, h:0.24, fontSize:11, bold:true, color:"888888", fontFace:FONT });
  s.addText(missionDate||"", { x:10.80, y:0.30, w:2.4, h:0.26, fontSize:10, bold:true, color:NAVY, fontFace:FONT });

  const TABLE_W = COL.reduce((a,b)=>a+b,0);
  s.addShape(pres.shapes.LINE, { x:TABLE_X, y:HEADER_H, w:TABLE_W, h:0, line:{color:BORDER,width:1.2} });

  const ho = (t) => ({ text:t, options:{ fill:{color:NAVY}, color:WHITE, bold:true, fontSize:12, align:"center", valign:"middle", fontFace:FONT }});
  const splitHdr = { text:[
    { text:"Total Duration", options:{ bold:true, color:WHITE, breakLine:true } },
    { text:"\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500", options:{ color:"7AADBD", fontSize:5, breakLine:true } },
    { text:"Transit Time", options:{ bold:true, color:WHITE } }
  ], options:{ fill:{color:NAVY}, fontSize:12, align:"center", valign:"middle", fontFace:FONT }};

  const rows = [[ ho("#"), ho("Day"), ho("Date"), ho("Airline"), ho("Departure"), ho("Arrival"), ho("Flight"), ho("Duration"), splitHdr, ho("Class") ]];
  const rowHArr = [0.72];

  for (const f of flights) {
    const bg = dateMap[f._bgKey]===0 ? WHITE : GREY;
    const c_ = (t,ex={}) => ({ text:t||"", options:{ fill:{color:bg}, color:DARK, fontSize:12, align:"center", valign:"middle", fontFace:FONT, ...ex }});
    const m_ = (t,ex={}) => ({ text:t||"", options:{ fill:{color:bg}, color:DARK, fontSize:12, align:"center", valign:"middle", fontFace:FONT, rowspan:2, ...ex }});
    const l0 = f.legs && f.legs[0];
    if (!l0) continue;
    if (f.direct) {
      rows.push([ m_(String(f.num),{color:DARK,fontSize:13}), m_(f.day||""), m_(f.date||""), m_(f.airline||"",{bold:true}), m_((l0.from||"")+"\n"+(l0.ft||"")), m_((l0.to||"")+"\n"+(l0.at||"")), m_(l0.no||""), m_(l0.dur||""), c_(l0.total||""), m_(" ") ]);
      rows.push([ { text:"Direct \u2192", options:{ fill:{color:DIRECT_BG}, color:"2E7D32", bold:true, fontSize:12, align:"center", valign:"middle", fontFace:FONT }} ]);
    } else {
      const l1=l0, l2=f.legs[1]||{};
      rows.push([ m_(String(f.num),{color:DARK,fontSize:13}), m_(f.day||""), m_(f.date||""), m_(f.airline||"",{bold:true}), c_((l1.from||"")+"\n"+(l1.ft||"")), c_((l1.to||"")+"\n"+(l1.at||"")), c_(l1.no||""), c_(l1.dur||""), c_(l1.total||""), m_(" ") ]);
      rows.push([ c_((l2.from||"")+"\n"+(l2.ft||"")), c_((l2.to||"")+"\n"+(l2.at||"")), c_(l2.no||""), c_(l2.dur||""), { text:l2.transit||"", options:{ fill:{color:TRANSIT_BG}, color:"CC0000", fontSize:12, align:"center", valign:"middle", fontFace:FONT }} ]);
    }
    rowHArr.push(ROW_H, ROW_H);
  }

  s.addTable(rows, { x:TABLE_X, y:HEADER_H+0.07, w:TABLE_W, colW:COL, rowH:rowHArr, border:{pt:0.5,color:BORDER}, autoPage:true, autoPageRepeatHeader:true, autoPageHeaderRows:1 });

  const clsColX=TABLE_X+COL.slice(0,9).reduce((a,b)=>a+b,0), clsW=COL[9];
  const ICON_S=0.26, GAP=0.08, TXT_W=0.95;
  const colMid=clsColX+clsW/2, iconX=colMid-(ICON_S+GAP+TXT_W)/2, textX=iconX+ICON_S+GAP;
  const cellH=2*ROW_H;
  let cy=HEADER_H+0.07+rowHArr[0];
  for (const f of flights) {
    if (!f.legs||!f.legs[0]) continue;
    const iy=cy+(cellH-ICON_S)/2;
    if (f.cls==="First")    s.addImage({ data:starPng, x:iconX, y:iy, w:ICON_S, h:ICON_S });
    if (f.cls==="Business") s.addImage({ data:bagPng,  x:iconX, y:iy, w:ICON_S, h:ICON_S });
    s.addText(f.cls||"Economy", { x:textX, y:cy, w:TXT_W, h:cellH, fontSize:12, color:DARK, fontFace:FONT, align:"left", valign:"middle", fill:{type:"none"}, line:{type:"none"} });
    cy+=cellH;
  }

  s.addShape(pres.shapes.LINE, { x:0.18, y:7.25, w:12.96, h:0, line:{color:BORDER,width:1.2} });
  s.addText("2", { x:12.6, y:7.28, w:0.5, h:0.2, fontSize:13, color:TEAL, fontFace:FONT, align:"right", valign:"middle" });

  // CLOSING
  const closing = pres.addSlide();
  closing.addImage({ data:CLOSING_IMG, x:0, y:0, w:13.33, h:7.5 });
  closing.addShape(pres.shapes.RECTANGLE, { x:BAND_X, y:BAND_Y, w:BAND_W, h:BAND_H, fill:{ type:"solid", color:BAND_COLOR, transparency:BAND_TRANS }, line:{ type:"none" } });
  closing.addImage({ data:LOGO_IMG, x:0.85, y:5.94, w:3.44, h:0.75 });
  closing.addText("Thank You", { x:4.6, y:BAND_Y, w:7.8, h:BAND_H, fontSize:32, bold:true, color:WHITE, fontFace:FONT, align:"right", valign:"middle" });

  return await pres.write({ outputType:"base64" });
}

// ── MAIN ENDPOINT ─────────────────────────────────────────────────────────────
app.post("/generate", async (req, res) => {
  try {
    const { legs, amadeusClientId, amadeusClientSecret, claudeKey } = req.body;
    if (!legs || !legs.length) return res.status(400).json({ error:"No legs provided" });

    // 1. Get Amadeus token
    const tokenRes = await getAmadeusToken(amadeusClientId, amadeusClientSecret);
    const token = tokenRes.access_token;
    if (!token) return res.status(500).json({ error:"Amadeus token failed", details: tokenRes });

    // 2. Search all legs and all dates
    const allOffers = [];
    for (const leg of legs) {
      for (let d = -1; d <= 1; d++) {
        const date = addDays(leg.date, d);
        const offers = await searchFlights(token, leg.from, leg.to, date);
        allOffers.push(...offers);
      }
    }

    // 3. Claude filter
    const flights = await claudeFilter(allOffers, claudeKey);

    // 4. Build labels
    const firstLeg = legs[0];
    const lastLeg  = legs[legs.length-1];
    const legLabel = firstLeg.from + " to " + lastLeg.to;
    const dates = flights.map(function(f){ return f.date; }).filter(Boolean).sort();
    const missionDate = dates.length > 1 ? dates[0] + " \u2013 " + dates[dates.length-1] : dates[0]||"";

    // 5. Generate PPTX
    const pptx = await generatePPTX(flights, legLabel, missionDate);
    res.json({ success:true, pptx:pptx });

  } catch(err) {
    console.error(err);
    res.status(500).json({ error: err.message });
  }
});

app.get("/", (req, res) => res.send("PPTX Server running \u2705"));

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log("Server running on port " + PORT));
